#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int sum = 0;
        for (int i = 0; i < n; i++) {
            sum += (a[i] + k - 1) / k;
        }
        printf("%d\n", sum);
    }
    return 0;
}

